export type HousingEra = 'pre-1950' | '1950s-1960s' | '1970s-1980s' | '1990s-2000s' | '2010s-present';
export type FloodRisk = 'low' | 'moderate' | 'high';
export type ValueTier = 'budget' | 'moderate' | 'upscale' | 'luxury';
export type Region = 'inner-loop' | 'inner-suburbs' | 'outer-suburbs' | 'exurban';
export type SoilType = 'clay' | 'sandy' | 'loam' | 'expansive-clay';
export type WaterHardness = 'soft' | 'moderate' | 'hard' | 'very-hard';

export interface SEOArea {
  name: string;
  slug: string;
  county: string;
  housingEra: HousingEra;
  floodRisk: FloodRisk;
  valueTier: ValueTier;
  region: Region;
  soilType: SoilType;
  waterHardness: WaterHardness;
  avgHomeAge: number;
  commonPipeType: string;
  typicalIssues: string[];
  nearbyLandmark: string;
  zipCode: string;
  populationDesc: string;
  housingStyle: string;
}

export interface SEOService {
  name: string;
  slug: string;
  category: string;
  avgCostLow: number;
  avgCostHigh: number;
  urgency: 'emergency' | 'urgent' | 'standard' | 'planned';
  shortDesc: string;
  longDesc: string;
  commonCauses: string[];
  signs: string[];
  whatToExpect: string[];
  preventionTips: string[];
  seasonalNote: string;
}

export interface SEOProblem {
  name: string;
  slug: string;
  urgency: 'call-now' | 'same-day' | 'this-week' | 'when-convenient';
  description: string;
  causes: string[];
  quickFixes: string[];
  whenToCallPro: string;
  relatedServices: string[];
  healthRisk: boolean;
  propertyDamageRisk: 'high' | 'moderate' | 'low';
}

// Helper to derive attributes from housing era
function deriveFromEra(era: HousingEra): { pipe: string; age: number; issues: string[]; style: string } {
  switch (era) {
    case 'pre-1950': return { pipe: 'galvanized steel', age: 85, issues: ['corroded galvanized pipes', 'lead solder joints', 'root intrusion in clay sewer lines', 'outdated fixtures'], style: 'Craftsman bungalows and early ranch homes' };
    case '1950s-1960s': return { pipe: 'cast iron and galvanized', age: 65, issues: ['deteriorating cast iron drains', 'orangeburg sewer pipe failure', 'galvanic corrosion', 'undersized water lines'], style: 'Mid-century ranch homes and split-levels' };
    case '1970s-1980s': return { pipe: 'copper with some polybutylene', age: 45, issues: ['copper pinhole leaks', 'polybutylene pipe failures', 'slab leaks from shifting soil', 'water heater sediment buildup'], style: 'Traditional two-story and patio homes' };
    case '1990s-2000s': return { pipe: 'CPVC and copper', age: 22, issues: ['CPVC brittleness from heat exposure', 'water heater replacement needs', 'faucet cartridge wear', 'toilet flapper deterioration'], style: 'Suburban tract homes and master-planned community houses' };
    case '2010s-present': return { pipe: 'PEX tubing', age: 8, issues: ['settling foundation affecting pipes', 'builder-grade fixture failures', 'warranty claim issues', 'tankless water heater descaling'], style: 'Modern open-concept homes and townhomes' };
  }
}

function deriveSoil(region: Region, county: string): SoilType {
  if (county === 'Galveston' || county === 'Chambers') return 'sandy';
  if (region === 'inner-loop') return 'expansive-clay';
  if (county === 'Fort Bend' || county === 'Brazoria') return 'clay';
  return 'loam';
}

function deriveWater(county: string): WaterHardness {
  if (['Harris', 'Fort Bend'].includes(county)) return 'hard';
  if (['Montgomery', 'Liberty'].includes(county)) return 'very-hard';
  if (county === 'Galveston') return 'moderate';
  return 'hard';
}

