// Helper to get area by slug
export function getAreaBySlug(slug: string): SEOArea | undefined {
  return seoAreas.find(a => a.slug === slug);
}

// Helper to get service by slug
export function getServiceBySlug(slug: string): SEOService | undefined {
  return seoServices.find(s => s.slug === slug);
}

// Helper to get problem by slug
export function getProblemBySlug(slug: string): SEOProblem | undefined {
  return seoProblems.find(p => p.slug === slug);
}
